/// Dispatch a `tools/call`. Returns the MCP `content` object or an error string.
pub fn call(engine: &Lodestar, params: &Value) -> Result<Value, String> {
    let name = params.get("name").and_then(Value::as_str).unwrap_or("");
    let args = params.get("arguments").cloned().unwrap_or(Value::Null);

    match name {
        "define_goal" => {
            let kind = parse_kind(req_str(&args, "kind")?)?;
            let goal = engine
                .define_goal(
                    kind,
                    req_str(&args, "title")?,
                    req_str(&args, "statement")?,
                    opt_str(&args, "parent_id"),
                )
                .map_err(|e| e.to_string())?;
            ok(&goal)
        }
        "supersede_goal" => {
            let goal = engine
                .supersede_goal(
                    req_str(&args, "goal_id")?,
                    req_str(&args, "new_statement")?,
                    req_str(&args, "reason")?,
                )
                .map_err(|e| e.to_string())?;
            ok(&goal)
        }
        "get_constitution" => ok(&engine.get_constitution().map_err(|e| e.to_string())?),
        "link_goal_to_code" => {
            let mode = parse_binding_mode(
                opt_str(&args, "mode")
                    .unwrap_or_else(|| "governed".to_string())
                    .as_str(),
            )?;
            let linked = engine
                .link_goal_to_code(
                    req_str(&args, "goal_id")?,
                    &str_array(&args, "node_ids"),
                    mode,
                )
                .map_err(|e| e.to_string())?;
            ok(&json!({ "linked": linked }))
        }
        "export_constitution" => {
            let md = engine
                .export_constitution(opt_str(&args, "path").as_deref())
                .map_err(|e| e.to_string())?;
            text(md)
        }
        "create_task" => {
            let task = engine
                .create_task_after(
                    req_str(&args, "goal_id")?,
                    req_str(&args, "title")?,
                    opt_str(&args, "acceptance").unwrap_or_default().as_str(),
                    optional_string_arg(&args, "blocked_by")?,
                )
                .map_err(|e| e.to_string())?;
            ok(&task)
        }
        "decompose_goal" => ok(&engine
            .decompose_goal(req_str(&args, "goal_id")?)
            .map_err(|e| e.to_string())?),
        "next_task" => match engine.next_task().map_err(|e| e.to_string())? {
            Some(t) => ok(&t),
            None => text("no claimable task".to_string()),
        },
        "claim_task" => {
            let won = engine
                .claim_task(
                    req_str(&args, "task_id")?,
                    opt_str(&args, "agent").unwrap_or_default().as_str(),
                    i64_arg(&args, "lease_secs", 300),
                )
                .map_err(|e| e.to_string())?;
            ok(&json!({ "won": won }))
        }
        "renew_lease" => {
            let renewed = engine
                .renew_lease(
                    req_str(&args, "task_id")?,
                    opt_str(&args, "agent").unwrap_or_default().as_str(),
                    i64_arg(&args, "lease_secs", 300),
                )
                .map_err(|e| e.to_string())?;
            ok(&json!({ "renewed": renewed }))
        }
        "complete_task" => {
            let evidence = parse_evidence(&args)?;
            let (completed, conformance) = engine
                .complete_task(
                    req_str(&args, "task_id")?,
                    opt_str(&args, "agent").unwrap_or_default().as_str(),
                    &evidence,
                )
                .map_err(|e| e.to_string())?;
            ok(&json!({ "completed": completed, "conformance": conformance }))
        }
        "release_task" => {
            let released = engine
                .release_task(
                    req_str(&args, "task_id")?,
                    opt_str(&args, "agent").unwrap_or_default().as_str(),
                )
                .map_err(|e| e.to_string())?;
            ok(&json!({ "released": released }))
        }
        "block_task" => {
            let blocked = engine
                .block_task(
                    req_str(&args, "task_id")?,
                    optional_string_arg(&args, "blocked_by")?,
                )
                .map_err(|e| e.to_string())?;
            ok(&json!({ "blocked": blocked }))
        }
        "reopen_task" => {
            let reopened = engine
                .reopen_task(req_str(&args, "task_id")?)
                .map_err(|e| e.to_string())?;
            ok(&json!({ "reopened": reopened }))
        }
        "board" => ok(&engine.board().map_err(|e| e.to_string())?),
        "check_conformance" => {
            let evidence = parse_evidence(&args)?;
            let result = engine
                .check_conformance(&evidence, opt_str(&args, "task_id").as_deref())
                .map_err(|e| e.to_string())?;
            ok(&result)
        }
        "conformance_history" => ok(&engine
            .conformance_history(req_str(&args, "task_id")?)
            .map_err(|e| e.to_string())?),
        "record_knowledge" => {
            let k = engine
                .record_knowledge(
                    req_str(&args, "statement")?,
                    opt_str(&args, "evidence")
                        .unwrap_or_else(|| "{}".to_string())
                        .as_str(),
                    args.get("half_life_hours").and_then(Value::as_f64),
                )
                .map_err(|e| e.to_string())?;
            ok(&k)
        }
        "consolidate" => {
            let promoted = engine
                .consolidate(
                    req_str(&args, "statement")?,
                    &str_array(&args, "evidence_node_ids"),
                    i64_arg(&args, "first_seen", 0),
                    i64_arg(&args, "last_seen", 0),
                )
                .map_err(|e| e.to_string())?;
            match promoted {
                Some(k) => ok(&k),
                None => text("not promoted: evidence below count/span threshold".to_string()),
            }
        }
        "active_knowledge" => ok(&engine.active_knowledge().map_err(|e| e.to_string())?),
        "reconfirm_knowledge" => {
            let reconfirmed = engine
                .reconfirm_knowledge(req_str(&args, "id")?)
                .map_err(|e| e.to_string())?;
            ok(&json!({ "reconfirmed": reconfirmed }))
        }
        "prune_knowledge" => {
            let pruned = engine.prune_knowledge().map_err(|e| e.to_string())?;
            ok(&json!({ "pruned": pruned }))
        }
        "lodestar_stats" => ok(&engine.stats().map_err(|e| e.to_string())?),
        "backup_database" => {
            let path = req_str(&args, "path")?;
            engine.backup_database(path).map_err(|e| e.to_string())?;
            ok(&json!({ "backed_up": true, "path": path }))
        }
        "reset_database" => {
            let outcome = engine
                .reset_database(req_str(&args, "confirm")?)
                .map_err(|e| e.to_string())?;
            ok(&outcome)
        }
        other => Err(format!("unknown tool: {other}")),
    }
}

// ---- helpers ---------------------------------------------------------------

fn parse_kind(s: &str) -> Result<GoalKind, String> {
    GoalKind::from_tag(s).ok_or_else(|| format!("invalid kind: {s}"))
}

fn parse_binding_mode(value: &str) -> Result<CodeBindingMode, String> {
    CodeBindingMode::from_tag(value).ok_or_else(|| format!("invalid code binding mode: {value}"))
}

fn parse_evidence(args: &Value) -> Result<ConformanceEvidence, String> {
    let evidence = args
        .get("evidence")
        .cloned()
        .ok_or_else(|| "missing required object arg: evidence".to_string())?;
    serde_json::from_value(evidence).map_err(|error| format!("invalid evidence: {error}"))
}

fn req_str<'a>(args: &'a Value, key: &str) -> Result<&'a str, String> {
    args.get(key)
        .and_then(Value::as_str)
        .ok_or_else(|| format!("missing required string arg: {key}"))
}

fn opt_str(args: &Value, key: &str) -> Option<String> {
    args.get(key)
        .and_then(Value::as_str)
        .filter(|s| !s.is_empty())
        .map(|s| s.to_string())
}

fn optional_string_arg(args: &Value, key: &str) -> Result<Option<String>, String> {
    match args.get(key) {
        None | Some(Value::Null) => Ok(None),
        Some(Value::String(value)) if !value.trim().is_empty() => Ok(Some(value.clone())),
        Some(Value::String(_)) => Err(format!("argument {key} must not be empty")),
        Some(_) => Err(format!("argument {key} must be a string")),
    }
}

fn i64_arg(args: &Value, key: &str, default: i64) -> i64 {
    args.get(key).and_then(Value::as_i64).unwrap_or(default)
}

fn str_array(args: &Value, key: &str) -> Vec<String> {
    args.get(key)
        .and_then(Value::as_array)
        .map(|a| {
            a.iter()
                .filter_map(|v| v.as_str().map(|s| s.to_string()))
                .collect()
        })
        .unwrap_or_default()
}

fn ok<T: Serialize>(value: &T) -> Result<Value, String> {
    let body = serde_json::to_string_pretty(value).map_err(|e| e.to_string())?;
    text(body)
}

fn text(body: String) -> Result<Value, String> {
    Ok(json!({ "content": [{ "type": "text", "text": body }] }))
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn tool_contract_requires_evidence_and_exposes_binding_mode() {
        let tools = list();
        let complete = tools
            .iter()
            .find(|tool| tool["name"] == "complete_task")
            .unwrap();
        assert!(complete["inputSchema"]["required"]
            .as_array()
            .unwrap()
            .iter()
            .any(|value| value == "evidence"));
        let link = tools
            .iter()
            .find(|tool| tool["name"] == "link_goal_to_code")
            .unwrap();
        assert_eq!(
            link["inputSchema"]["properties"]["mode"]["default"],
            "governed"
        );
        let create = tools
            .iter()
            .find(|tool| tool["name"] == "create_task")
            .unwrap();
        assert!(create["inputSchema"]["properties"]["blocked_by"].is_object());
    }

    #[test]
    fn malformed_evidence_is_rejected_at_the_tool_boundary() {
        let engine = Lodestar::open_in_memory().unwrap();
        let params = json!({
            "name": "check_conformance",
            "arguments": { "evidence": { "schema_version": 1 } }
        });
        assert!(call(&engine, &params)
            .unwrap_err()
            .contains("invalid evidence"));
    }

    #[test]
    fn lifecycle_tools_backup_and_require_lodestar_reset_token() {
        let engine = Lodestar::open_in_memory().unwrap();
        engine
            .define_goal(
                GoalKind::Invariant,
                "Keep intent durable",
                "Never erase intent with memory reset",
                None,
            )
            .unwrap();
        let path =
            std::env::temp_dir().join(format!("lodestar-mcp-backup-{}.db", std::process::id()));
        let _ = std::fs::remove_file(&path);

        call(
            &engine,
            &json!({
                "name": "backup_database",
                "arguments": { "path": path.to_str().unwrap() }
            }),
        )
        .unwrap();
        let restored = Lodestar::open(path.to_str().unwrap()).unwrap();
        assert_eq!(restored.get_constitution().unwrap().len(), 1);
        drop(restored);
        std::fs::remove_file(path).unwrap();

        let rejected = call(
            &engine,
            &json!({
                "name": "reset_database",
                "arguments": { "confirm": "RESET MINDLEAK" }
            }),
        )
        .unwrap_err();
        assert!(rejected.contains("RESET LODESTAR"));
        call(
            &engine,
            &json!({
                "name": "reset_database",
                "arguments": { "confirm": "RESET LODESTAR" }
            }),
        )
        .unwrap();
        assert!(engine.get_constitution().unwrap().is_empty());
    }

    #[test]
    fn create_task_dispatch_accepts_a_predecessor() {
        let engine = Lodestar::open_in_memory().unwrap();
        let goal = engine
            .define_goal(GoalKind::Objective, "Handoff", "serialize edits", None)
            .unwrap();
        let first = engine.create_task(&goal.id, "First", "done").unwrap();

        let result = call(
            &engine,
            &json!({
                "name": "create_task",
                "arguments": {
                    "goal_id": goal.id,
                    "title": "Second",
                    "acceptance": "done",
                    "blocked_by": first.id
                }
            }),
        )
        .unwrap();
        let task: Value =
            serde_json::from_str(result["content"][0]["text"].as_str().unwrap()).unwrap();

        assert_eq!(task["status"], "blocked");
        assert!(task["blocked_by"].as_str().unwrap().starts_with("task:"));
    }

    #[test]
    fn reopen_task_dispatch_returns_a_manual_hold_to_open() {
        let engine = Lodestar::open_in_memory().unwrap();
        let goal = engine
            .define_goal(GoalKind::Objective, "Recover", "unstick work", None)
            .unwrap();
        let task = engine.create_task(&goal.id, "Held", "done").unwrap();
        // A manual hold with no predecessor was previously unrecoverable via the
        // tool surface; reopen_task must return it to a claimable state.
        engine.block_task(&task.id, None).unwrap();

        let result = call(
            &engine,
            &json!({ "name": "reopen_task", "arguments": { "task_id": task.id } }),
        )
        .unwrap();
        let payload: Value =
            serde_json::from_str(result["content"][0]["text"].as_str().unwrap()).unwrap();
        assert_eq!(payload["reopened"], true);

        let board = engine.board().unwrap();
        let reopened = board.iter().find(|t| t.id == task.id).unwrap();
        assert_eq!(reopened.status.as_str(), "open");
    }

    #[test]
    fn conformance_history_dispatch_returns_the_audit_chain() {
        let engine = Lodestar::open_in_memory().unwrap();
        let goal = engine
            .define_goal(GoalKind::Objective, "History", "prove it", None)
            .unwrap();
        let task = engine.create_task(&goal.id, "work", "done").unwrap();

        // No checks yet -> empty chain.
        let empty = call(
            &engine,
            &json!({ "name": "conformance_history", "arguments": { "task_id": task.id } }),
        )
        .unwrap();
        let records: Value =
            serde_json::from_str(empty["content"][0]["text"].as_str().unwrap()).unwrap();
        assert!(records.as_array().unwrap().is_empty());
    }

    #[test]
    fn create_task_rejects_malformed_predecessor_and_preserves_legacy_calls() {
        let engine = Lodestar::open_in_memory().unwrap();
        let goal = engine
            .define_goal(GoalKind::Objective, "Handoff", "serialize edits", None)
            .unwrap();
        let malformed = json!({
            "name": "create_task",
            "arguments": {
                "goal_id": goal.id,
                "title": "Unsafe",
                "blocked_by": 42
            }
        });
        assert!(call(&engine, &malformed)
            .unwrap_err()
            .contains("must be a string"));

        let legacy = call(
            &engine,
            &json!({
                "name": "create_task",
                "arguments": { "goal_id": goal.id, "title": "Legacy" }
            }),
        )
        .unwrap();
        let task: Value =
            serde_json::from_str(legacy["content"][0]["text"].as_str().unwrap()).unwrap();
        assert_eq!(task["status"], "open");
        assert!(task["blocked_by"].is_null());
    }
}
